export function getWaypointsForRoute(slug: string): WaypointData[] {
  return waypointsByRoute[slug] ?? []
}

export function getStampWaypointsForRoute(slug: string, limit = 5): WaypointData[] {
  return (waypointsByRoute[slug] ?? [])
    .filter(w => w.hasStamp && w.stampDescription?.en)
    .sort((a, b) => a.stageNumber - b.stageNumber)
    .slice(0, limit)
}
